diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..8075deb859d3 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3328,9 +3328,68 @@ static Value *foldAndOrOfICmpEqConstantAndICmp(ICmpInst *LHS, ICmpInst *RHS,
       Other);
 }

-/// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
-/// If IsLogical is true, then the and/or is in select form and the transform
-/// must be poison-safe.
+// (icmp eq X, C1) | (icmp eq (X & Mask), C2) -> (icmp ult (X - C1), Size + 1)
+// where C2 = C1 + 1 and Mask creates a contiguous range starting at C2.
+// For example, (icmp eq X, 127) | (icmp eq (X & -32), 128) -> (icmp ult (X - 127), 33)
+static Value *foldOrOfICmpEqConstantAndICmpWithMask(ICmpInst *LHS,
+                                                     ICmpInst *RHS,
+                                                     bool IsAnd,
+                                                     bool IsLogical,
+                                                     IRBuilderBase &Builder) {
+  // Only handle OR, not AND.
+  if (IsAnd)
+    return nullptr;
+
+  // Match (icmp eq X, C1).
+  CmpPredicate Pred;
+  Value *X;
+  const APInt *C1;
+  if (!match(LHS, m_ICmp(Pred, m_Value(X), m_APInt(C1))) ||
+      Pred != ICmpInst::ICMP_EQ)
+    return nullptr;
+
+  // Compute C2 = C1 + 1.
+  APInt C2 = *C1 + 1;
+
+  // Match (icmp eq (X & Mask), C2).
+  Value *MaskedX;
+  const APInt *MaskC;
+  if (!match(RHS, m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
+                         m_SpecificInt(C2))) ||
+      Pred != ICmpInst::ICMP_EQ)
+    return nullptr;
+
+  // For (X & Mask) == C2 to represent a contiguous range starting at C2:
+  // 1. C2 must be a power of 2 (so it has a single bit at the boundary)
+  // 2. Mask must preserve the single bit in C2, i.e., (Mask & C2) == C2
+  // 3. The trailing zeros in Mask define the range size
+
+  // Check that C2 is a power of 2.
+  if (!C2.isPowerOf2())
+    return nullptr;
+
+  // Check that the mask preserves C2.
+  if (!(*MaskC & C2).eq(C2))
+    return nullptr;
+
+  // Calculate the range size from trailing zeros of Mask.
+  // Each trailing zero in Mask adds a factor of 2 to the range.
+  unsigned BitWidth = MaskC->getBitWidth();
+  unsigned TrailingZeros = MaskC->countTrailingZeros();
+
+  // The total range covered is [C1, C2 + 2^TrailingZeros).
+  // We can represent this as (X - C1) u< (2^TrailingZeros + 1).
+  APInt RangeSizePlusOne = APInt(BitWidth, 1);
+  RangeSizePlusOne <<= TrailingZeros;
+  RangeSizePlusOne += 1;
+
+  // Transform: (icmp ult (X - C1), RangeSizePlusOne)
+  if (IsLogical && !isGuaranteedNotToBeUndefOrPoison(X))
+    X = Builder.CreateFreeze(X);
+
+  Value *Sub = Builder.CreateSub(X, ConstantInt::get(X->getType(), *C1));
+  return Builder.CreateICmpULT(Sub, ConstantInt::get(X->getType(), RangeSizePlusOne));
+}
 Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
                                           Instruction &I, bool IsAnd,
                                           bool IsLogical) {
@@ -3368,6 +3427,15 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
                                                   /*IsLogical*/ false, Builder))
     return V;

+  // Handle (icmp eq X, C1) | (icmp eq (X & Mask), C2) where C2 = C1 + 1
+  // and Mask creates a contiguous range starting at C2.
+  if (Value *V = foldOrOfICmpEqConstantAndICmpWithMask(LHS, RHS, IsAnd,
+                                                        IsLogical, Builder))
+    return V;
+  if (Value *V = foldOrOfICmpEqConstantAndICmpWithMask(RHS, LHS, IsAnd,
+                                                        IsLogical, Builder))
+    return V;
+
   if (Value *V =
           foldAndOrOfICmpsWithConstEq(LHS, RHS, IsAnd, IsLogical, Builder, Q))
     return V;

