// (icmp eq X, C1) | (icmp eq (X & Mask), C2) -> (icmp ult (X - C1), Size + 1)
// where C2 = C1 + 1 and Mask creates a contiguous range starting at C2.
// For example, (icmp eq X, 127) | (icmp eq (X & -32), 128) -> (icmp ult (X - 127), 33)
static Value *foldOrOfICmpEqConstantAndICmpWithMask(ICmpInst *LHS,
                                                     ICmpInst *RHS,
                                                     bool IsAnd,
                                                     bool IsLogical,
                                                     IRBuilderBase &Builder) {
  // Only handle OR, not AND.
  if (IsAnd)
    return nullptr;

  // Match (icmp eq X, C1).
  Value *X;
  const APInt *C1;
  if (!match(LHS, m_ICmp(ICmpInst::ICMP_EQ, m_Value(X), m_APInt(C1))))
    return nullptr;

  // Compute C2 = C1 + 1.
  APInt C2 = *C1 + 1;

  // Match (icmp eq (X & Mask), C2).
  Value *Mask;
  const APInt *MaskC;
  if (!match(RHS, m_ICmp(ICmpInst::ICMP_EQ,
                         m_And(m_Specific(X), m_APInt(MaskC)),
                         m_SpecificInt(C2))))
    return nullptr;

  // Ensure Mask is compatible with C2:
  // (Mask & ((C2 - 1) | C2)) == C2
  // This ensures that the mask preserves all significant bits of C2
  // and creates a contiguous range starting at C2.
  APInt LowerBits = C2 - 1;
  if ((*MaskC & (LowerBits | C2)) != C2)
    return nullptr;

  // Calculate the range size: 2^tzcnt(~Mask)
  unsigned TrailingZeros = (~*MaskC).countTrailingZeros();
  APInt RangeSize = APInt(C1->getBitWidth(), 1);
  RangeSize <<= TrailingZeros;

  // The total covered range is C1 plus the range starting at C2,
  // so the total size is RangeSize + 1.
  // Transform: (icmp ult (X - C1), RangeSize + 1)
  if (IsLogical && !isGuaranteedNotToBeUndefOrPoison(X))
    X = Builder.CreateFreeze(X);

  Value *Sub = Builder.CreateSub(X, ConstantInt::get(X->getType(), *C1));
  return Builder.CreateICmpULT(Sub, ConstantInt::get(X->getType(), RangeSize + 1));
}
